#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            int y = 1 - x;
            if(i) printf(" ");
            printf("%d", y);
        }
        printf("\n");
    }
    return 0;
}

